import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"Установка Java на macOS","description":"Пошаговое руководство по установке Java на macOS.","frontmatter":{"title":"Установка Java на macOS","description":"Пошаговое руководство по установке Java на macOS.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"ru_ru/players/installing-java/macos.md","filePath":"translated/ru_ru/players/installing-java/macos.md","lastUpdated":1770561656000}`);var c={name:`ru_ru/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка Java на macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка Java на macOS”">​</a></h1><p>Это руководство поможет вам установить Java 21 на macOS.</p><p>Minecraft Launcher поставляется с собственной установкой Java, поэтому этот раздел актуален только в том случае, если вы хотите использовать установщик Fabric на основе <code>.jar</code> или Minecraft Server <code>.jar</code>.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Проверьте, установлена ли Java <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Проверьте, установлена ли Java”">​</a></h2><p>В Терминале (расположенном в <code>/Applications/Utilities/Terminal.app</code>) введите следующее и нажмите <kbd>Enter</kbd>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Вы должны увидеть что-то вроде следующего:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Обратите внимание на номер версии: в приведенном выше примере это <code>21.0.9</code>.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Чтобы использовать Minecraft 1.21.11, вам понадобится как минимум Java 21.</p><p>Если эта команда отображает версию ниже 21, вам необходимо обновить существующую Java; продолжайте читать эту страницу.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Загрузка и установка Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Загрузка и установка Java 21”">​</a></h2><p>Мы рекомендуем использовать <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">сборку OpenJDK 21 от Adoptium</a>:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Страница загрузки Java для Temurin" loading="lazy"></p><p>Обязательно выберите версию «21 — LTS» и формат установщика <code>.PKG</code>. Вы также должны выбрать правильную архитектуру в зависимости от чипа вашей системы:</p><ul><li>Если у вас чип Apple серии M, выберите <code>aarch64</code> (по умолчанию)</li><li>Если у вас процессор Intel, выберите <code>x64</code></li><li>Следуйте этим <a href="https://support.apple.com/en-us/116943" target="_blank" rel="noreferrer">инструкциям, чтобы узнать, какой чип установлен в вашем Mac</a></li></ul><p>После загрузки установщика <code>.pkg</code> откройте его и следуйте инструкциям:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Установщик Java от Temurin" loading="lazy"></p><p>Для завершения установки необходимо ввести пароль администратора:</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="Запрос пароля macOS" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Использование Homebrew <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Использование Homebrew”">​</a></h3><p>Если у вас уже установлен <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>, вы можете установить Java 21 с помощью <code>brew</code>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Убедитесь, что Java 21 установлена <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Убедитесь, что Java 21 установлена”">​</a></h2><p>После завершения установки вы можете убедиться, что Java 21 активна, открыв терминал снова и введя <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code>.</p><p>Если команда выполнена успешно, вы должны увидеть примерно следующее:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Если у вас возникнут проблемы, не стесняйтесь обращаться за помощью в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> в канале <code>#player-support</code>.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};